                                    <div>
                                        <label className="block text-xs font-medium">3-Month</label>
                                        <input type="number" className="w-full border rounded px-2 py-1" value={currentPlan.pricing?.quarterly || ''} onChange={e => setCurrentPlan({...currentPlan, pricing: {...currentPlan.pricing!, quarterly: Number(e.target.value)}})} />
