```typescript
import { Program, Coach, BlogPost, Offer, Lead, SiteSettings, Testimonial, MembershipTier, PlanInquiry, FreeResource, LegalPage, CounselingService } from '../types.ts';
import { SEED_PROGRAMS, SEED_COACHES, SEED_BLOGS, SEED_OFFERS, SEED_SETTINGS, SEED_TESTIMONIALS, SEED_MEMBERSHIPS, SEED_FREE_RESOURCES, SEED_LEGAL_PAGES, SEED_COUNSELING } from '../constants.ts';

const DB_NAME = 'AthletesAuraDB';
const DB_VERSION = 1;

const STORES = {
  PROGRAMS: 'programs',
  COACHES: 'coaches',
  BLOGS: 'blogs',
  OFFERS: 'offers',
  LEADS: 'leads',
  SETTINGS: 'settings',
  TESTIMONIALS: 'testimonials',
  MEMBERSHIPS: 'memberships',
  PLAN_INQUIRIES: 'plan_inquiries',
  FREE_RESOURCES: 'free_resources',
  LEGAL_PAGES: 'legal_pages',
  COUNSELING: 'counseling',
  AUTH: 'auth',
};

// --- Low Level IndexedDB Wrapper ---
const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      Object.values(STORES).forEach(storeName => {
        if (!db.objectStoreNames.contains(storeName)) {
          // Use 'id' as keyPath for everything except settings/auth which are singletons
          if (storeName === STORES.SETTINGS || storeName === STORES.AUTH) {
             db.createObjectStore(storeName);
          } else {
             db.createObjectStore(storeName, { keyPath: 'id' });
          }
        }
      });
    };

    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

const dbOp = async <T>(storeName: string, mode: IDBTransactionMode, callback: (store: IDBObjectStore) => IDBRequest<T> | void): Promise<T> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(storeName, mode);
    const store = tx.objectStore(storeName);
    const request = callback(store);

    tx.oncomplete = () => resolve((request as IDBRequest<T>)?.result);
    tx.onerror = () => reject(tx.error);
  });
};

// --- Helper for Singletons (Settings/Auth) ---
const getSingleton = async <T>(storeName: string, key: string, defaultVal: T): Promise<T> => {
    const db = await openDB();
    return new Promise((resolve) => {
        const tx = db.transaction(storeName, 'readonly');
        const store = tx.objectStore(storeName);
        const req = store.get(key);
        req.onsuccess = () => resolve(req.result || defaultVal);
        req.onerror = () => resolve(defaultVal);
    });
};

const saveSingleton = async <T>(storeName: string, key: string, val: T): Promise<void> => {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(storeName, 'readwrite');
        const store = tx.objectStore(storeName);
        store.put(val, key);
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });
};

// --- Hashing ---
async function sha256(message: string): Promise<string> {
  const msgBuffer = new TextEncoder().encode(message);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

// --- Public API ---
export const StorageService = {
  init: async () => {
    // Check if seeded
    const isSeeded = await getSingleton(STORES.SETTINGS, 'seeded_v1.9', false);

    if (!isSeeded) {
       console.log('Seeding IndexedDB data...');
       const db = await openDB();
       const tx = db.transaction(Object.values(STORES), 'readwrite');

       // Bulk Seed
       SEED_PROGRAMS.forEach(i => tx.objectStore(STORES.PROGRAMS).put(i));
       SEED_COACHES.forEach(i => tx.objectStore(STORES.COACHES).put(i));
       SEED_BLOGS.forEach(i => tx.objectStore(STORES.BLOGS).put(i));
       SEED_OFFERS.forEach(i => tx.objectStore(STORES.OFFERS).put(i));
       SEED_TESTIMONIALS.forEach(i => tx.objectStore(STORES.TESTIMONIALS).put(i));
       SEED_MEMBERSHIPS.forEach(i => tx.objectStore(STORES.MEMBERSHIPS).put(i));
       SEED_FREE_RESOURCES.forEach(i => tx.objectStore(STORES.FREE_RESOURCES).put(i));
       SEED_LEGAL_PAGES.forEach(i => tx.objectStore(STORES.LEGAL_PAGES).put(i));
       SEED_COUNSELING.forEach(i => tx.objectStore(STORES.COUNSELING).put(i));

       tx.objectStore(STORES.SETTINGS).put(SEED_SETTINGS, 'config');
       tx.objectStore(STORES.SETTINGS).put(true, 'seeded_v1.9');

       const defaultAuth = {
            passwordHash: '240be518fabd2724ddb6f04eeb1da5967448d7e831c08c8fa822809f74c720a9', // admin123
            securityPhraseHash: '', 
       };
       tx.objectStore(STORES.AUTH).put(defaultAuth, 'credentials');
    }
  },

  // Generics
  getAll: (store: string) => dbOp(store, 'readonly', s => s.getAll()),
  save: (store: string, item: any) => dbOp(store, 'readwrite', s => s.put(item)),
  saveAll: async (store: string, items: any[]) => {
      const db = await openDB();
      const tx = db.transaction(store, 'readwrite');
      const s = tx.objectStore(store);
      s.clear(); // Simple replacement strategy
      items.forEach(i => s.put(i));
      return new Promise<void>((resolve) => { tx.oncomplete = () => resolve(); });
  },
  delete: (store: string, id: string) => dbOp(store, 'readwrite', s => s.delete(id)),

  // Specific Accessors
  getPrograms: async (): Promise<Program[]> => (await StorageService.getAll(STORES.PROGRAMS)) || [],
  savePrograms: (items: Program[]) => StorageService.saveAll(STORES.PROGRAMS, items),

  getCoaches: async (): Promise<Coach[]> => (await StorageService.getAll(STORES.COACHES)) || [],
  saveCoaches: (items: Coach[]) => StorageService.saveAll(STORES.COACHES, items),

  getBlogs: async (): Promise<BlogPost[]> => (await StorageService.getAll(STORES.BLOGS)) || [],
  saveBlogs: (items: BlogPost[]) => StorageService.saveAll(STORES.BLOGS, items),

  getOffers: async (): Promise<Offer[]> => (await StorageService.getAll(STORES.OFFERS)) || [],
  saveOffers: (items: Offer[]) => StorageService.saveAll(STORES.OFFERS, items),

  getTestimonials: async (): Promise<Testimonial[]> => (await StorageService.getAll(STORES.TESTIMONIALS)) || [],
  saveTestimonials: (items: Testimonial[]) => StorageService.saveAll(STORES.TESTIMONIALS, items),

  getMemberships: async (): Promise<MembershipTier[]> => (await StorageService.getAll(STORES.MEMBERSHIPS)) || [],
  saveMemberships: (items: MembershipTier[]) => StorageService.saveAll(STORES.MEMBERSHIPS, items),

  getLeads: async (): Promise<Lead[]> => (await StorageService.getAll(STORES.LEADS)) || [],
  addLead: (item: Lead) => StorageService.save(STORES.LEADS, item),
  deleteLead: (id: string) => StorageService.delete(STORES.LEADS, id),

  getPlanInquiries: async (): Promise<PlanInquiry[]> => (await StorageService.getAll(STORES.PLAN_INQUIRIES)) || [],
  addPlanInquiry: (item: PlanInquiry) => StorageService.save(STORES.PLAN_INQUIRIES, item),
  deletePlanInquiry: (id: string) => StorageService.delete(STORES.PLAN_INQUIRIES, id),

  getFreeResources: async (): Promise<FreeResource[]> => (await StorageService.getAll(STORES.FREE_RESOURCES)) || [],
  saveFreeResources: (items: FreeResource[]) => StorageService.saveAll(STORES.FREE_RESOURCES, items),

  getLegalPages: async (): Promise<LegalPage[]> => (await StorageService.getAll(STORES.LEGAL_PAGES)) || [],
  saveLegalPages: (items: LegalPage[]) => StorageService.saveAll(STORES.LEGAL_PAGES, items),

  getCounselingServices: async (): Promise<CounselingService[]> => (await StorageService.getAll(STORES.COUNSELING)) || [],
  saveCounselingServices: (items: CounselingService[]) => StorageService.saveAll(STORES.COUNSELING, items),

  getSettings: async (): Promise<SiteSettings> => getSingleton(STORES.SETTINGS, 'config', SEED_SETTINGS),
  saveSettings: (settings: SiteSettings) => saveSingleton(STORES.SETTINGS, 'config', settings),

  // Auth
  verifyPassword: async (input: string): Promise<boolean> => {
    const authData = await getSingleton(STORES.AUTH, 'credentials', { passwordHash: '' });
    const inputHash = await sha256(input);
    return inputHash === authData.passwordHash;
  },

  verifySecurityPhrase: async (input: string): Promise<boolean> => {
    const authData = await getSingleton(STORES.AUTH, 'credentials', { securityPhraseHash: '' });
    if (!authData.securityPhraseHash) return false;
    const inputHash = await sha256(input.trim().toLowerCase());
    return inputHash === authData.securityPhraseHash;
  },

  updatePassword: async (newPass: string) => {
    const authData = await getSingleton(STORES.AUTH, 'credentials', { passwordHash: '', securityPhraseHash: '' });
    authData.passwordHash = await sha256(newPass);
    await saveSingleton(STORES.AUTH, 'credentials', authData);
  },

  setSecurityPhrase: async (phrase: string) => {
    const authData = await getSingleton(STORES.AUTH, 'credentials', { passwordHash: '', securityPhraseHash: '' });
    authData.securityPhraseHash = await sha256(phrase.trim().toLowerCase());
    await saveSingleton(STORES.AUTH, 'credentials', authData);
  }
};
