Here is the **Full Step-by-Step Guide** to setting up your Athletes Aura website with a **PHP/MySQL backend** using XAMPP on your local system.

I have also updated the **Backend Code (PHP/SQL)** to ensure it handles **Base64 images** (which can be large) and **CORS** (Cross-Origin Resource Sharing) correctly so your Vite development server can talk to the XAMPP server.

---

### **Part 1: The Backend Code (PHP & SQL)**

You need to create a folder in your XAMPP `htdocs` directory. Let's call it `athlete_backend`.

#### 1. Database Schema
Save this as `schema.sql`. Note that I have changed image columns to `LONGTEXT` to support the Base64 image uploads you requested.

```sql
-- schema.sql

CREATE DATABASE IF NOT EXISTS athletes_aura_db;
USE athletes_aura_db;

-- Settings (Singleton)
CREATE TABLE IF NOT EXISTS settings (
    id INT PRIMARY KEY DEFAULT 1,
    data LONGTEXT NOT NULL -- Stores the entire JSON settings object
);

-- Auth (Singleton)
CREATE TABLE IF NOT EXISTS auth (
    id INT PRIMARY KEY DEFAULT 1,
    password_hash VARCHAR(255),
    security_phrase_hash VARCHAR(255)
);

-- Programs
CREATE TABLE IF NOT EXISTS programs (
    id VARCHAR(50) PRIMARY KEY,
    name VARCHAR(255),
    description TEXT,
    category VARCHAR(100),
    price VARCHAR(50),
    discount_percentage INT,
    image LONGTEXT, -- LONGTEXT for Base64
    is_enabled TINYINT(1)
);

-- Coaches
CREATE TABLE IF NOT EXISTS coaches (
    id VARCHAR(50) PRIMARY KEY,
    name VARCHAR(255),
    role VARCHAR(255),
    experience VARCHAR(100),
    certifications TEXT,
    achievements TEXT,
    image LONGTEXT,
    socials TEXT -- JSON string
);

-- Blogs
CREATE TABLE IF NOT EXISTS blogs (
    id VARCHAR(50) PRIMARY KEY,
    title VARCHAR(255),
    description TEXT,
    content LONGTEXT,
    author VARCHAR(100),
    date VARCHAR(50),
    image LONGTEXT
);

-- Offers
CREATE TABLE IF NOT EXISTS offers (
    id VARCHAR(50) PRIMARY KEY,
    title VARCHAR(255),
    description TEXT,
    image LONGTEXT,
    discount_text VARCHAR(50),
    is_enabled TINYINT(1)
);

-- Testimonials
CREATE TABLE IF NOT EXISTS testimonials (
    id VARCHAR(50) PRIMARY KEY,
    name VARCHAR(255),
    role VARCHAR(100),
    content TEXT,
    image LONGTEXT
);

-- Membership Tiers
CREATE TABLE IF NOT EXISTS memberships (
    id VARCHAR(50) PRIMARY KEY,
    name VARCHAR(255),
    description TEXT,
    features TEXT, -- JSON Array
    highlight TINYINT(1),
    pricing TEXT -- JSON Object
);

-- Leads
CREATE TABLE IF NOT EXISTS leads (
    id VARCHAR(50) PRIMARY KEY,
    name VARCHAR(255),
    email VARCHAR(255),
    phone VARCHAR(50),
    interest VARCHAR(100),
    message TEXT,
    date DATETIME
);

-- Plan Inquiries
CREATE TABLE IF NOT EXISTS plan_inquiries (
    id VARCHAR(50) PRIMARY KEY,
    name VARCHAR(255),
    email VARCHAR(255),
    phone VARCHAR(50),
    type VARCHAR(50),
    goals TEXT,
    date DATETIME
);

-- Free Resources
CREATE TABLE IF NOT EXISTS free_resources (
    id VARCHAR(50) PRIMARY KEY,
    title VARCHAR(255),
    type VARCHAR(50),
    link TEXT,
    description TEXT
);

-- Legal Pages
CREATE TABLE IF NOT EXISTS legal_pages (
    id VARCHAR(50) PRIMARY KEY,
    title VARCHAR(255),
    slug VARCHAR(255),
    content LONGTEXT,
    is_visible TINYINT(1)
);

-- Counseling Services
CREATE TABLE IF NOT EXISTS counseling (
    id VARCHAR(50) PRIMARY KEY,
    title VARCHAR(255),
    description TEXT,
    price INT,
    duration VARCHAR(50),
    image LONGTEXT,
    is_enabled TINYINT(1)
);
```

#### 2. Database Configuration
Save this as `db_config.php` inside `athlete_backend`.

```php
<?php
// db_config.php
$host = 'localhost';
$db   = 'athletes_aura_db';
$user = 'root'; // Default XAMPP user
$pass = '';     // Default XAMPP password is empty
$charset = 'utf8mb4';

$dsn = "mysql:host=$host;dbname=$db;charset=$charset";
$options = [
    PDO::ATTR_ERRMODE            => PDO::ERRMODE_EXCEPTION,
    PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
    PDO::ATTR_EMULATE_PREPARES   => false,
];

try {
    $pdo = new PDO($dsn, $user, $pass, $options);
} catch (\PDOException $e) {
    // If DB doesn't exist, try to create it (first run logic)
    try {
        $pdo = new PDO("mysql:host=$host", $user, $pass);
        $pdo->exec("CREATE DATABASE IF NOT EXISTS `$db`");
        $pdo->exec("USE `$db`");
        // We won't run the full schema here, user should import schema.sql
    } catch (\PDOException $e2) {
        throw new \PDOException($e2->getMessage(), (int)$e2->getCode());
    }
}
?>
```

#### 3. Main API Handler
Save this as `api.php` inside `athlete_backend`. This handles the React requests.

```php
<?php
// api.php
header("Access-Control-Allow-Origin: *");
header("Access-Control-Allow-Headers: Content-Type");
header("Access-Control-Allow-Methods: GET, POST, DELETE, OPTIONS");

if ($_SERVER['REQUEST_METHOD'] === 'OPTIONS') {
    http_response_code(200);
    exit();
}

require 'db_config.php';

$method = $_SERVER['REQUEST_METHOD'];
$endpoint = $_GET['endpoint'] ?? '';
$id = $_GET['id'] ?? null;

// Map endpoints to table names
$tables = [
    'programs' => 'programs',
    'coaches' => 'coaches',
    'blogs' => 'blogs',
    'offers' => 'offers',
    'testimonials' => 'testimonials',
    'memberships' => 'memberships',
    'leads' => 'leads',
    'plan_inquiries' => 'plan_inquiries',
    'free_resources' => 'free_resources',
    'legal_pages' => 'legal_pages',
    'counseling' => 'counseling',
    'settings' => 'settings',
    'auth' => 'auth'
];

if (!array_key_exists($endpoint, $tables)) {
    echo json_encode(['error' => 'Invalid endpoint']);
    exit;
}

$table = $tables[$endpoint];

// Helper to convert complex fields to JSON for DB
function processInput($data) {
    $fields = [];
    foreach ($data as $key => $value) {
        if (is_array($value) || is_object($value)) {
            $fields[$key] = json_encode($value);
        } else {
            $fields[$key] = $value;
        }
    }
    return $fields;
}

// Helper to expand JSON fields from DB
function processOutput($row) {
    $jsonFields = ['socials', 'features', 'pricing', 'data']; // 'data' is for settings
    foreach ($row as $key => $value) {
        if (in_array($key, $jsonFields) || ($key === 'is_enabled') || ($key === 'is_visible') || ($key === 'highlight')) {
             if (in_array($key, $jsonFields)) {
                 $decoded = json_decode($value, true);
                 $row[$key] = $decoded ? $decoded : $value;
             }
             // Convert tinyint to boolean for React
             if (in_array($key, ['is_enabled', 'is_visible', 'highlight'])) {
                 $row[$key] = (bool)$value;
             }
        }
        // Handle CamelCase conversion for specific DB columns if needed
        if ($key === 'discount_text') { $row['discountText'] = $value; unset($row['discount_text']); }
        if ($key === 'discount_percentage') { $row['discountPercentage'] = $value; unset($row['discount_percentage']); }
        if ($key === 'is_enabled') { $row['isEnabled'] = (bool)$value; unset($row['is_enabled']); }
        if ($key === 'is_visible') { $row['isVisible'] = (bool)$value; unset($row['is_visible']); }
        if ($key === 'password_hash') { $row['passwordHash'] = $value; unset($row['password_hash']); }
        if ($key === 'security_phrase_hash') { $row['securityPhraseHash'] = $value; unset($row['security_phrase_hash']); }
    }
    // Special case for Settings wrapper
    if (isset($row['data'])) return $row['data'];

    return $row;
}

try {
    if ($method === 'GET') {
        if ($table === 'settings' || $table === 'auth') {
            $stmt = $pdo->prepare("SELECT * FROM $table WHERE id = 1");
            $stmt->execute();
            $result = $stmt->fetch();
            echo json_encode($result ? processOutput($result) : null);
        } else {
            $stmt = $pdo->query("SELECT * FROM $table");
            $data = $stmt->fetchAll();
            $processed = array_map('processOutput', $data);
            echo json_encode($processed);
        }
    } 
    elseif ($method === 'POST') {
        $input = json_decode(file_get_contents('php://input'), true);

        if ($table === 'settings' || $table === 'auth') {
            // Upsert for Singletons
            $jsonVal = json_encode($input);
            if ($table === 'settings') {
                $sql = "INSERT INTO settings (id, data) VALUES (1, ?) ON DUPLICATE KEY UPDATE data = ?";
                $stmt = $pdo->prepare($sql);
                $stmt->execute([$jsonVal, $jsonVal]);
            } else {
                // Auth is specific columns
                $pass = $input['passwordHash'] ?? '';
                $sec = $input['securityPhraseHash'] ?? '';
                $sql = "INSERT INTO auth (id, password_hash, security_phrase_hash) VALUES (1, ?, ?) ON DUPLICATE KEY UPDATE password_hash = ?, security_phrase_hash = ?";
                $stmt = $pdo->prepare($sql);
                $stmt->execute([$pass, $sec, $pass, $sec]);
            }
            echo json_encode(['success' => true]);
        } else {
            // Upsert for others
            $processed = processInput($input);

            // Map camelCase keys back to snake_case DB columns
            if(isset($processed['discountText'])) { $processed['discount_text'] = $processed['discountText']; unset($processed['discountText']); }
            if(isset($processed['discountPercentage'])) { $processed['discount_percentage'] = $processed['discountPercentage']; unset($processed['discountPercentage']); }
            if(isset($processed['isEnabled'])) { $processed['is_enabled'] = $processed['isEnabled'] ? 1 : 0; unset($processed['isEnabled']); }
            if(isset($processed['isVisible'])) { $processed['is_visible'] = $processed['isVisible'] ? 1 : 0; unset($processed['isVisible']); }

            $columns = array_keys($processed);
            $placeholders = array_fill(0, count($columns), '?');
            $updates = [];
            foreach ($columns as $col) {
                $updates[] = "$col = VALUES($col)";
            }

            $sql = "INSERT INTO $table (" . implode(', ', $columns) . ") VALUES (" . implode(', ', $placeholders) . ") ON DUPLICATE KEY UPDATE " . implode(', ', $updates);

            $stmt = $pdo->prepare($sql);
            $stmt->execute(array_values($processed));
            echo json_encode(['success' => true]);
        }
    } 
    elseif ($method === 'DELETE') {
        if ($id && $table !== 'settings' && $table !== 'auth') {
            $stmt = $pdo->prepare("DELETE FROM $table WHERE id = ?");
            $stmt->execute([$id]);
            echo json_encode(['success' => true]);
        } else {
            echo json_encode(['error' => 'Missing ID or restricted table']);
        }
    }
} catch (PDOException $e) {
    http_response_code(500);
    echo json_encode(['error' => $e->getMessage()]);
}
?>
```

