```tsx
import React, { useState, useRef } from 'react';
import { Upload, Link as LinkIcon, Image as ImageIcon, X } from 'lucide-react';

interface Props {
    value: string;
    onChange: (val: string) => void;
    label?: string;
}

export const ImageInput: React.FC<Props> = ({ value, onChange, label = "Image" }) => {
    const [mode, setMode] = useState<'url' | 'upload'>('url');
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            if (file.size > 500 * 1024) {
                alert("File size must be less than 500KB");
                return;
            }
            const reader = new FileReader();
            reader.onloadend = () => {
                onChange(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    return (
        <div className="space-y-2">
            <label className="block text-sm font-medium text-gray-700">{label}</label>

            {/* Preview Area */}
            <div className="flex items-center space-x-4 mb-2">
                <div className="h-20 w-20 bg-gray-100 rounded border flex items-center justify-center overflow-hidden relative">
                    {value ? (
                        <>
                            <img src={value} alt="Preview" className="h-full w-full object-cover" />
                            <button 
                                type="button"
                                onClick={() => onChange('')}
                                className="absolute top-0 right-0 bg-red-500 text-white p-0.5 rounded-bl hover:bg-red-600"
                            >
                                <X className="h-3 w-3" />
                            </button>
                        </>
                    ) : (
                        <ImageIcon className="h-8 w-8 text-gray-400" />
                    )}
                </div>

                <div className="flex-1">
                    <div className="flex space-x-2 mb-2">
                        <button 
                            type="button" 
                            onClick={() => setMode('url')}
                            className={`px-3 py-1 text-xs font-bold rounded flex items-center ${mode === 'url' ? 'bg-black text-white' : 'bg-gray-200 text-gray-700'}`}
                        >
                            <LinkIcon className="h-3 w-3 mr-1" /> URL
                        </button>
                        <button 
                            type="button" 
                            onClick={() => setMode('upload')}
                            className={`px-3 py-1 text-xs font-bold rounded flex items-center ${mode === 'upload' ? 'bg-black text-white' : 'bg-gray-200 text-gray-700'}`}
                        >
                            <Upload className="h-3 w-3 mr-1" /> Upload
                        </button>
                    </div>

                    {mode === 'url' ? (
                        <input 
                            type="text" 
                            className="w-full border rounded px-3 py-2 text-sm" 
                            placeholder="https://example.com/image.jpg"
                            value={value.startsWith('data:') ? '' : value}
                            onChange={(e) => onChange(e.target.value)}
                        />
                    ) : (
                        <input 
                            ref={fileInputRef}
                            type="file" 
                            accept="image/*"
                            className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-semibold file:bg-black file:text-white hover:file:bg-gray-800"
                            onChange={handleFileChange}
                        />
                    )}
                    <p className="text-xs text-gray-500 mt-1">
                        {mode === 'upload' ? "Max size: 500KB. Formats: JPG, PNG, WEBP" : "Paste a direct link to an image."}
                    </p>
                </div>
            </div>
        </div>
    );
};
