```typescript
import { Program, Coach, BlogPost, Offer, Lead, SiteSettings, Testimonial, MembershipTier, PlanInquiry, FreeResource, LegalPage, CounselingService } from '../types.ts';
import { SEED_PROGRAMS, SEED_COACHES, SEED_BLOGS, SEED_OFFERS, SEED_SETTINGS, SEED_TESTIMONIALS, SEED_MEMBERSHIPS, SEED_FREE_RESOURCES, SEED_LEGAL_PAGES, SEED_COUNSELING } from '../constants.ts';

const API_URL = 'http://localhost:8080/athlete_backend/api.php';

const api = {
    get: async (endpoint: string) => {
        try {
            const res = await fetch(`${API_URL}?endpoint=${endpoint}`);
            if (!res.ok) {
                // ... logging ...
                throw new Error(`HTTP error! status: ${res.status}`);
            }
            const text = await res.text();
            try {
                if (!text) return null;
                return JSON.parse(text);
            } catch (e) {
                console.error("Failed to parse JSON response:", text);
                return null;
            }
        } catch (e) {
            console.error(`API Connection Error (${endpoint}):`, e);
            return null;
        }
    },
    post: async (endpoint: string, data: any) => {
        try {
            const res = await fetch(`${API_URL}?endpoint=${endpoint}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data)
            });

            // Handle Rate Limiting (429) specially
            if (res.status === 429) {
                const json = await res.json();
                return { error: json.error || 'Too many attempts. Please wait.' };
            }

            const text = await res.text();
            try {
                const json = JSON.parse(text);
                if (json.error) {
                    console.error("Backend returned error:", json.error);
                    return { error: json.error };
                }
                return json;
            } catch (e) {
                return { error: 'Invalid response from server' };
            }
        } catch (e) {
            return { error: true };
        }
    },
    delete: async (endpoint: string, id: string) => {
        try {
            const res = await fetch(`${API_URL}?endpoint=${endpoint}&id=${id}`, {
                method: 'DELETE'
            });
            return await res.json();
        } catch (e) {
            return { error: true };
        }
    },
    checkConnection: async (): Promise<boolean> => {
        try {
            const res = await fetch(`${API_URL}?endpoint=settings`);
            if (res.ok) {
                const text = await res.text();
                if (text.includes('<b>Fatal error</b>') || text.includes('<b>Warning</b>')) return false;
                return true;
            }
            return false;
        } catch (e) {
            return false;
        }
    }
};

async function sha256(message: string): Promise<string> {
  const msgBuffer = new TextEncoder().encode(message);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

export const StorageService = {
  init: async () => {
    try {
        const isConnected = await api.checkConnection();
        if (!isConnected) return;

        const settings = await api.get('settings');

        if (settings === null) {
            console.log('Seeding Content...');
            for(const p of SEED_PROGRAMS) await api.post('programs', p);
            for(const c of SEED_COACHES) await api.post('coaches', c);
            for(const b of SEED_BLOGS) await api.post('blogs', b);
            for(const o of SEED_OFFERS) await api.post('offers', o);
            for(const t of SEED_TESTIMONIALS) await api.post('testimonials', t);
            for(const m of SEED_MEMBERSHIPS) await api.post('memberships', m);
            for(const f of SEED_FREE_RESOURCES) await api.post('free_resources', f);
            for(const l of SEED_LEGAL_PAGES) await api.post('legal_pages', l);
            for(const cs of SEED_COUNSELING) await api.post('counseling', cs);
            await api.post('settings', SEED_SETTINGS);
        }

        const auth = await api.get('auth');
        if (auth === null || !auth.passwordHash) {
            console.log('Seeding Admin Credentials...');
            const defaultAuth = {
                passwordHash: '240be518fabd2724ddb6f04eeb1da5967448d7e831c08c8fa822809f74c720a9', // admin123
                securityPhraseHash: '', 
            };
            await api.post('auth', defaultAuth);
        }
    } catch (e) {
        console.error("Failed to initialize storage.", e);
    }
  },

  checkConnection: api.checkConnection,

  getPrograms: async (): Promise<Program[]> => (await api.get('programs')) || [],
  saveProgram: async (item: Program) => { await api.post('programs', item); },
  deleteProgram: async (id: string) => { await api.delete('programs', id); },

  getCoaches: async (): Promise<Coach[]> => (await api.get('coaches')) || [],
  saveCoach: async (item: Coach) => { await api.post('coaches', item); },
  deleteCoach: async (id: string) => { await api.delete('coaches', id); },

  getBlogs: async (): Promise<BlogPost[]> => (await api.get('blogs')) || [],
  saveBlog: async (item: BlogPost) => { await api.post('blogs', item); },
  deleteBlog: async (id: string) => { await api.delete('blogs', id); },

  getOffers: async (): Promise<Offer[]> => (await api.get('offers')) || [],
  saveOffer: async (item: Offer) => { await api.post('offers', item); },
  deleteOffer: async (id: string) => { await api.delete('offers', id); },

  getTestimonials: async (): Promise<Testimonial[]> => (await api.get('testimonials')) || [],
  saveTestimonial: async (item: Testimonial) => { await api.post('testimonials', item); },
  deleteTestimonial: async (id: string) => { await api.delete('testimonials', id); },

  getMemberships: async (): Promise<MembershipTier[]> => (await api.get('memberships')) || [],
  saveMembership: async (item: MembershipTier) => { await api.post('memberships', item); },
  deleteMembership: async (id: string) => { await api.delete('memberships', id); },

  getLeads: async (): Promise<Lead[]> => (await api.get('leads')) || [],
  addLead: async (item: Lead) => { await api.post('leads', item); },
  deleteLead: async (id: string) => { await api.delete('leads', id); },

  getPlanInquiries: async (): Promise<PlanInquiry[]> => (await api.get('plan_inquiries')) || [],
  addPlanInquiry: async (item: PlanInquiry) => { await api.post('plan_inquiries', item); },
  deletePlanInquiry: async (id: string) => { await api.delete('plan_inquiries', id); },

  getFreeResources: async (): Promise<FreeResource[]> => (await api.get('free_resources')) || [],
  saveFreeResource: async (item: FreeResource) => { await api.post('free_resources', item); },
  deleteFreeResource: async (id: string) => { await api.delete('free_resources', id); },

  getLegalPages: async (): Promise<LegalPage[]> => (await api.get('legal_pages')) || [],
  saveLegalPage: async (item: LegalPage) => { await api.post('legal_pages', item); },
  deleteLegalPage: async (id: string) => { await api.delete('legal_pages', id); },

  getCounselingServices: async (): Promise<CounselingService[]> => (await api.get('counseling')) || [],
  saveCounselingService: async (item: CounselingService) => { await api.post('counseling', item); },
  deleteCounselingService: async (id: string) => { await api.delete('counseling', id); },

  getSettings: async (): Promise<SiteSettings> => {
      const s = await api.get('settings');
      return { ...SEED_SETTINGS, ...s };
  },
  saveSettings: async (settings: SiteSettings) => { await api.post('settings', settings); },

  // Updated to support returning objects (errors)
  verifyPassword: async (input: string): Promise<boolean | {error: string}> => {
    // We send a POST request with the password so the backend can count attempts
    // Sending hash to backend for verification is safer for throttling
    const inputHash = await sha256(input);
    const result = await api.post('auth/verify', { passwordHash: inputHash });

    if (result.error) return { error: result.error };
    return result.success === true;
  },

  verifySecurityPhrase: async (input: string): Promise<boolean> => {
    const authData = await api.get('auth');
    if (!authData || !authData.securityPhraseHash) return false;
    const inputHash = await sha256(input.trim().toLowerCase());
    return inputHash === authData.securityPhraseHash;
  },

  updatePassword: async (newPass: string) => {
    const authData = (await api.get('auth')) || {};
    authData.passwordHash = await sha256(newPass);
    await api.post('auth', authData);
  },

  setSecurityPhrase: async (phrase: string) => {
    const authData = (await api.get('auth')) || {};
    authData.securityPhraseHash = await sha256(phrase.trim().toLowerCase());
    await api.post('auth', authData);
  }
};
