Includes `auth/verify` logic, rate limiting, and exception handling for JSON.

```php
<?php
// api.php

// 1. Handle CORS (Cross-Origin Resource Sharing)
header("Access-Control-Allow-Origin: *");
header("Access-Control-Allow-Headers: Content-Type, Access-Control-Allow-Headers, Authorization, X-Requested-With");
header("Access-Control-Allow-Methods: GET, POST, DELETE, OPTIONS");
header('Content-Type: application/json');

// Handle Pre-flight requests
if ($_SERVER['REQUEST_METHOD'] === 'OPTIONS') {
    http_response_code(200);
    exit();
}

require 'db_config.php';

$method = $_SERVER['REQUEST_METHOD'];
$endpoint = $_GET['endpoint'] ?? '';
$id = $_GET['id'] ?? null;

// --- Security Helper Functions ---

function getClientIP() {
    return $_SERVER['REMOTE_ADDR'] ?? 'UNKNOWN';
}

function checkLoginThrottle($pdo) {
    $ip = getClientIP();
    // Count failed attempts in the last 15 minutes
    $stmt = $pdo->prepare("SELECT COUNT(*) FROM login_attempts WHERE ip_address = ? AND success = 0 AND attempt_time > (NOW() - INTERVAL 15 MINUTE)");
    $stmt->execute([$ip]);
    $attempts = $stmt->fetchColumn();

    if ($attempts >= 3) {
        // Calculate wait time: 30 seconds * (attempts - 2)
        // e.g. 3 attempts = 30s, 4 attempts = 60s, etc.
        return true; 
    }
    return false;
}

function recordLoginAttempt($pdo, $success) {
    $ip = getClientIP();
    $stmt = $pdo->prepare("INSERT INTO login_attempts (ip_address, attempt_time, success) VALUES (?, NOW(), ?)");
    $stmt->execute([$ip, $success ? 1 : 0]);
}

// Map endpoints to table names
$tables = [
    'programs' => 'programs',
    'coaches' => 'coaches',
    'blogs' => 'blogs',
    'offers' => 'offers',
    'testimonials' => 'testimonials',
    'memberships' => 'memberships',
    'leads' => 'leads',
    'plan_inquiries' => 'plan_inquiries',
    'free_resources' => 'free_resources',
    'legal_pages' => 'legal_pages',
    'counseling' => 'counseling',
    'settings' => 'settings',
    'auth' => 'auth'
];

// --- Handle Custom Endpoints ---

// Security Verification Endpoint
if ($endpoint === 'auth/verify' && $method === 'POST') {
    $input = json_decode(file_get_contents('php://input'), true);

    if (checkLoginThrottle($pdo)) {
        http_response_code(429); // Too Many Requests
        echo json_encode(['error' => 'Too many failed attempts. Please wait 30 seconds before trying again.']);
        exit;
    }

    $providedHash = $input['passwordHash'] ?? '';

    $stmt = $pdo->prepare("SELECT password_hash FROM auth WHERE id = 1");
    $stmt->execute();
    $authRow = $stmt->fetch();

    if ($authRow && $authRow['password_hash'] === $providedHash) {
        recordLoginAttempt($pdo, true);
        echo json_encode(['success' => true]);
    } else {
        recordLoginAttempt($pdo, false);
        echo json_encode(['success' => false, 'error' => 'Invalid credentials']);
    }
    exit;
}

// Standard CRUD Validation
if (!array_key_exists($endpoint, $tables)) {
    http_response_code(400);
    echo json_encode(['error' => 'Invalid endpoint']);
    exit;
}

$table = $tables[$endpoint];

// Helper: Convert inputs to JSON for storage
function processInput($data) {
    $fields = [];
    foreach ($data as $key => $value) {
        if (is_array($value) || is_object($value)) {
            $fields[$key] = json_encode($value);
        } else {
            // Basic XSS Protection: Strip tags, but ALLOW HTML for Content/Image fields
            if (is_string($value) && !in_array($key, ['content', 'image', 'data', 'logoUrl', 'faviconUrl'])) {
                $fields[$key] = strip_tags($value); 
            } else {
                $fields[$key] = $value;
            }
        }
    }
    return $fields;
}

// Helper: Expand JSON from DB
function processOutput($row) {
    $jsonFields = ['socials', 'features', 'pricing', 'data']; 
    foreach ($row as $key => $value) {
        if (in_array($key, $jsonFields)) {
             $decoded = json_decode($value, true);
             $row[$key] = ($decoded !== null) ? $decoded : ($key === 'data' ? [] : $value);
        }
        if (in_array($key, ['is_enabled', 'is_visible', 'highlight'])) {
             $row[$key] = (bool)$value;
        }
        if ($key === 'discount_text') { $row['discountText'] = $value; unset($row['discount_text']); }
        if ($key === 'discount_percentage') { $row['discountPercentage'] = $value; unset($row['discount_percentage']); }
        if ($key === 'is_enabled') { $row['isEnabled'] = (bool)$value; unset($row['is_enabled']); }
        if ($key === 'is_visible') { $row['isVisible'] = (bool)$value; unset($row['is_visible']); }
        if ($key === 'password_hash') { $row['passwordHash'] = $value; unset($row['password_hash']); }
        if ($key === 'security_phrase_hash') { $row['securityPhraseHash'] = $value; unset($row['security_phrase_hash']); }
    }
    if (isset($row['data'])) return $row['data'];
    return $row;
}

try {
    if ($method === 'GET') {
        if ($table === 'settings' || $table === 'auth') {
            $stmt = $pdo->prepare("SELECT * FROM $table WHERE id = 1");
            $stmt->execute();
            $result = $stmt->fetch();
            echo json_encode($result ? processOutput($result) : null);
        } else {
            $stmt = $pdo->query("SELECT * FROM $table");
            $data = $stmt->fetchAll();
            $processed = array_map('processOutput', $data);
            echo json_encode($processed);
        }
    } 
    elseif ($method === 'POST') {
        $rawInput = file_get_contents('php://input');
        $input = json_decode($rawInput, true);

        if (json_last_error() !== JSON_ERROR_NONE) {
             http_response_code(400);
             echo json_encode(['error' => 'Invalid JSON input']);
             exit;
        }

        if ($table === 'settings' || $table === 'auth') {
            if ($table === 'settings') {
                $jsonVal = json_encode($input);
                $sql = "INSERT INTO settings (id, data) VALUES (1, ?) ON DUPLICATE KEY UPDATE data = ?";
                $stmt = $pdo->prepare($sql);
                $stmt->execute([$jsonVal, $jsonVal]);
            } else {
                $pass = $input['passwordHash'] ?? '';
                $sec = $input['securityPhraseHash'] ?? '';
                $sql = "INSERT INTO auth (id, password_hash, security_phrase_hash) VALUES (1, ?, ?) ON DUPLICATE KEY UPDATE password_hash = ?, security_phrase_hash = ?";
                $stmt = $pdo->prepare($sql);
                $stmt->execute([$pass, $sec, $pass, $sec]);
            }
            echo json_encode(['success' => true]);
        } else {
            $processed = processInput($input);
            if(isset($processed['discountText'])) { $processed['discount_text'] = $processed['discountText']; unset($processed['discountText']); }
            if(isset($processed['discountPercentage'])) { $processed['discount_percentage'] = $processed['discountPercentage']; unset($processed['discountPercentage']); }
            if(isset($processed['isEnabled'])) { $processed['is_enabled'] = $processed['isEnabled'] ? 1 : 0; unset($processed['isEnabled']); }
            if(isset($processed['isVisible'])) { $processed['is_visible'] = $processed['isVisible'] ? 1 : 0; unset($processed['isVisible']); }

            $columns = array_keys($processed);
            $placeholders = array_fill(0, count($columns), '?');
            $updates = [];
            foreach ($columns as $col) {
                $updates[] = "$col = VALUES($col)";
            }

            $sql = "INSERT INTO $table (" . implode(', ', $columns) . ") VALUES (" . implode(', ', $placeholders) . ") ON DUPLICATE KEY UPDATE " . implode(', ', $updates);
            $stmt = $pdo->prepare($sql);
            $stmt->execute(array_values($processed));
            echo json_encode(['success' => true]);
        }
    } 
    elseif ($method === 'DELETE') {
        if ($id && $table !== 'settings' && $table !== 'auth') {
            $stmt = $pdo->prepare("DELETE FROM $table WHERE id = ?");
            $stmt->execute([$id]);
            echo json_encode(['success' => true]);
        } else {
            http_response_code(400);
            echo json_encode(['error' => 'Missing ID or restricted table']);
        }
    }
} catch (PDOException $e) {
    http_response_code(500);
    echo json_encode(['error' => $e->getMessage()]);
}
?>
